package main

import (
	"fmt"
	"testing"
)

type Book struct {
	Title string
	ISBN  string
}

type Library struct {
	Books []Book
}

func (l Library) countBooks() int {
	return len(l.Books)
}

func safeCount(l Library, t *testing.T) int {
	if l.Books == nil {
		t.Fatalf("Library.Books is nil — cannot count")
	}
	return l.countBooks()
}

func main() {
	t := &testing.T{}
	lib1 := Library{Books: nil}
	c1 := safeCount(lib1, t)
	fmt.Printf("count = %d\n", c1)

	lib2 := Library{Books: []Book{{"A", "1"}, {"B", "2"}}}
	c2 := safeCount(lib2, t)
	fmt.Printf("count = %d\n", c2)
	fmt.Println("All count tests passed")
}

