```
tests := []struct {
    input string
    want  *Book
}{
    {"978-123", &Book{"Go 101", "978-123"}},
    {"missing", nil},
}
for _, tt := range tests {
    got := lib.lookupByISBN(tt.input)
    ...
}
```

