package main

import (
	"fmt"
	"testing"
)

type Book struct {
	Title string
	ISBN  string
}

type Library struct {
	Books []Book
}

func (l Library) lookupByISBN(isbn string) *Book {
	for _, b := range l.Books {
		if b.ISBN == isbn {
			return &b
		}
	}
	return nil
}

func TestLookupByISBN(t *testing.T) {
	lib := Library{Books: []Book{
		{"Go 101", "978-123"},
		{"Testing In Go", "978-789"},
	}}

	tests := []struct {
		isbn string
		want *Book
	}{
		{"978-123", &Book{"Go 101", "978-123"}},
		// TODO: add {"000-000", nil} and {"978-789", &Book{"Testing In Go", "978-789"}}
	}

	passed := 0
	for _, tt := range tests {
		got := lib.lookupByISBN(tt.isbn)
		if (got == nil) != (tt.want == nil) || (got != nil && got.ISBN != tt.want.ISBN) {
			t.Errorf("lookupByISBN(%q) = %v, want %v", tt.isbn, got, tt.want)
		} else {
			passed++
		}
	}
	fmt.Printf("%d/%d cases passed\n", passed, len(tests))
}

func main() {
	TestLookupByISBN(&testing.T{})
}

