package main

import (
	"fmt"
	"strings"
	"testing"
)

type Book struct {
	Title string
	ISBN  string
}

type Library []Book

func (lib Library) lookupLinear(isbn string) *Book {
	for _, b := range lib {
		if b.ISBN == isbn {
			return &b
		}
	}
	return nil
}

func (lib Library) lookupMap(index map[string]*Book, isbn string) *Book {
	return index[isbn]
}

func BenchmarkLinear(b *testing.B) {
	lib := Library{
		{"A", "1"}, {"B", "2"}, {"C", "3"}, {"D", "4"}, {"E", "5"},
	}
	for i := 0; i < b.N; i++ {
		lib.lookupLinear("5")
	}
}

func BenchmarkMapLookup(b *testing.B) {
	lib := Library{
		{"A", "1"}, {"B", "2"}, {"C", "3"}, {"D", "4"}, {"E", "5"},
	}
	index := make(map[string]*Book)
	for i := range lib {
		index[lib[i].ISBN] = &lib[i]
	}
	for i := 0; i < b.N; i++ {
		lib.lookupMap(index, "5")
	}
}

func main() {
	// Run a quick comparison manually
	fmt.Println("linear:", len(Library{{"A", "1"}}), "books")
	fmt.Println("map:", len(Library{{"B", "2"}}), "books")
}

